import React from "react"
import { Route, Switch } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';

import './App.css';
import Navbar from "./components/CustomNavbar/CustomNavbar"
import Home from "./components/Home/Home"
import PublicPolls from "./components/PublicPolls/PublicPolls"
import CreatePolls from "./components/CreatePolls/CreatePolls"
import Vote from "./components/Vote/Vote" 
import Results from "./components/Results/Results" 
import Login from "./components/Login/Login"
import Register from "./components/Register/Register"

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <nav>
          <Navbar />
        </nav>
      </header>
      <main>
        <Switch >
          <Route path="/" exact component={Home} />
          <Route path="/public" exact component={PublicPolls} />
          <Route path="/poll/new" exact component={CreatePolls} />
          <Route path="/results/:id" exact component={Results} />
          <Route path="/poll/:id" exact component={Vote} />
          <Route path="/login" exact component={Login} />
          <Route path="/register" exact component={Register} />
        </Switch>
      </main>
    </div>
  );
}

export default App;
